class Solution:
    def eventualSafeNodes(self, graph):
        from collections import deque
        n = len(graph)
        rev = [[] for _ in range(n)]
        outdeg = [0] * n
        for u in range(n):
            outdeg[u] = len(graph[u])
            for v in graph[u]:
                rev[v].append(u)
        q = deque(i for i in range(n) if outdeg[i] == 0)
        safe = [False] * n
        while q:
            u = q.popleft()
            safe[u] = True
            for w in rev[u]:
                outdeg[w] -= 1
                if outdeg[w] == 0:
                    q.append(w)
        return [i for i in range(n) if safe[i]]

