var eventualSafeNodes = function(graph) {
    const n = graph.length;
    const rev = Array.from({ length: n }, () => []);
    const outdeg = new Array(n).fill(0);
    for (let u = 0; u < n; u++) {
        outdeg[u] = graph[u].length;
        for (const v of graph[u]) rev[v].push(u);
    }
    const q = [];
    for (let i = 0; i < n; i++) if (outdeg[i] === 0) q.push(i);
    const safe = new Array(n).fill(false);
    let head = 0;
    while (head < q.length) {
        const u = q[head++];
        safe[u] = true;
        for (const w of rev[u]) {
            if (--outdeg[w] === 0) q.push(w);
        }
    }
    const res = [];
    for (let i = 0; i < n; i++) if (safe[i]) res.push(i);
    return res;
};
